#!/usr/bin/env python3 import enhanced_rft_crypto def debug_8byte(): # Create cipher instance cipher = enhanced_rft_crypto.PyEnhancedRFTCrypto() # Test with exactly 8 bytes (triggers padding logic) key = b"testkey123456789" # 16 bytes plaintext = b"12345678" # 8 bytes - will trigger padding code print("=== 8-byte Input Debug ===") print(f"Plaintext (8 bytes): {plaintext.hex()}") # Encrypt encrypted = cipher.encrypt(plaintext, key) print(f"Encrypted: {encrypted.hex()}") # Decrypt decrypted = cipher.decrypt(encrypted, key) print(f"Decrypted: {decrypted.hex()}") # Check match match = decrypted == plaintext print(f"Match: {match}") if not match: print("Mismatch details:") for i in range(len(plaintext)): if i < len(decrypted) and decrypted[i] != plaintext[i]: print(f" Byte {i}: {plaintext[i]:02x} -> {decrypted[i]:02x}") if __name__ == "__main__": debug_8byte() 